INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (326, 'Austria', 'AT', 'Vienna', 8316487, 'Austria is divided into nine Bundesländer, or simply Länder (states; sing. Land).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (327, 'Belgium', 'BE', 'Bruxelles', 10584534, 'Belgium is divided into ten provinces (Flemish: provincies) and one capital region (Flemish: hoofdstedelijke gewest; French: région capitale).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (328, 'Denmark', 'DK', 'Copenhagen', 5475791, 'Denmark is divided into five regioner (regions; singular: region) and 98 municipalities (Danish, kommuner).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (329, 'Finland', 'FI', 'Helsinki', 5311891, 'Finland is divided into five läänit (sing. lääni, Swedish län: provinces) and one itsehallinnollinen maakunta (autonomous province), namely Åland. ', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (330, 'France', 'FR', 'Paris', 64473140, 'France, in Europe and adjacent islands (Corsica), is divided into 96 départements (departments). It also has a number of possessions, some of which are classified as départements d''outre-mer (overseas departments). ', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (331, 'Germany', 'DE', 'Berlin', 82210000, 'Germany is divided into sixteen Länder (sing. Land: state).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (332, 'Ireland', 'IE', 'Dublin', 6000000, 'Ireland is divided into 26 (traditional) counties.', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (333, 'Italy', 'IT', 'Roma', 59536507, 'Italy is divided into 110 province (sing. provincia: provinces).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (334, 'Netherlands', 'NL', 'Amsterdam', 16408557, 'The Netherlands is divided into twelve provincies (provinces).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (335, 'Norway', 'NO', 'Oslo', 4752735, 'Norway is divided into 19 fylker (sing. fylke: counties).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (336, 'Poland', 'PL', 'Warsaw', 38518241, 'Poland is divided into sixteen wojewodztwa (voivodships).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (337, 'Portugal', 'PT', 'Lisbon', 10623032, 'Portugal is divided into eighteen distritos (districts) and two regiões autônomas (autonomous regions).', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (338, 'Spain', 'ES', 'Madrid', 45200737, 'Spain is politically organized into 17 Autonomous Communities (comunidades autónomas) and 2 autonomous cities (ciudades autónomas) - Ceuta and Melilla. Administratively Spain also comprises fifty provinces.', 53);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (339, 'Sweden', 'SE', 'Stockholm', 91962274, 'Sweden is divided into 21 län (counties).', 53);
