INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (343, 'Mexico', 'MX', 'Mexico D.F.', 108700891, 'Mexico is divided into 31 estados (states) and one distrito federal (federal district).', 54);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (344, 'United States', 'USA', 'Washington D.C.', 304358000, 'The United States is divided into fifty states and one federal district.', 54);
