INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (346, 'Japan', 'JP', 'Tokyo', 127433494, 'Japan is divided into 43 ken (prefectures), one to (metropolis - Tokyo), one do (Area - Hokkaido), and two fu (urban prefectures - Kyoto and Osaka). The four words are combined in one, todofuken, to denote a division of any type.', 55);
INSERT INTO Country (CountryKey, CountryName, CountryCode, CountryCapital, Population, Subdivision, ContinentKey) VALUES (347, 'Singapore', 'SG', 'Singapore', 4588600, 'Singapore is divided into five districts.', 55);
