/****** Table State ******/
CREATE TABLE State(
	StateKey int GENERATED BY DEFAULT AS IDENTITY,
	StateName varchar(40) NOT NULL,
	EnglishStateName varchar(40) NULL,
	StateType varchar(40) NOT NULL,
	StateCode varchar(3) NULL,
	StateCapital varchar(40) NULL,
	RegionName varchar(40) NULL,
	RegionCode varchar(3) NULL,
	CountryKey int NOT NULL,
	CONSTRAINT PK_State_StateKey PRIMARY KEY (StateKey)
);

/****** Table Country ******/
CREATE TABLE Country(
	CountryKey int GENERATED BY DEFAULT AS IDENTITY,
	CountryName varchar(40) NOT NULL,
	CountryCode varchar(3) NOT NULL,
	CountryCapital varchar(40) NOT NULL,
	Population int NULL,
	Subdivision text NULL,
	ContinentKey int NOT NULL,
	CONSTRAINT PK_Country_CountryKey PRIMARY KEY (CountryKey)
);

/****** Table Continent ******/
CREATE TABLE Continent(
	ContinentKey int GENERATED BY DEFAULT AS IDENTITY,
	ContinentName varchar(20) NOT NULL,
	CONSTRAINT PK_Continent_ContinentKey PRIMARY KEY (ContinentKey)
);

/****** Table City ******/
CREATE TABLE City(
	CityKey int GENERATED BY DEFAULT AS IDENTITY,
	CityName varchar(40) NOT NULL,
	StateKey int NOT NULL,
	CONSTRAINT PK_City_CityKey PRIMARY KEY (CityKey)
);

/****** Table Supplier ******/
CREATE TABLE Supplier(
	SupplierKey int NOT NULL,
	CompanyName varchar(40) NOT NULL,
	Address varchar(60) NULL,
	PostalCode varchar(10) NULL,
	CityKey int NULL,
	CONSTRAINT PK_Supplier_SupplierKey PRIMARY KEY (SupplierKey)
);

/****** Table Customer ******/
CREATE TABLE Customer(
	CustomerKey int GENERATED BY DEFAULT AS IDENTITY,
	CustomerID char(5) NOT NULL,
	CompanyName varchar(40) NOT NULL,
	Address varchar(60) NULL,
	PostalCode varchar(10) NULL,
	CityKey int NULL,
	CONSTRAINT PK_Customer_CustomerKey PRIMARY KEY (CustomerKey)
);

/****** Table Category ******/
CREATE TABLE Category(
	CategoryKey int NOT NULL,
	CategoryName varchar(15) NOT NULL,
	Description text NULL,
	CONSTRAINT PK_Category_CategoryKey PRIMARY KEY (CategoryKey)
);

/****** Table Product ******/
CREATE TABLE Product(
	ProductKey int NOT NULL,
	ProductName varchar(40) NOT NULL,
	QuantityPerUnit varchar(20) NULL,
	UnitPrice money NULL,
	Discontinued bit NOT NULL,
	CategoryKey int NULL,
	CONSTRAINT PK_Product_ProductKey PRIMARY KEY (ProductKey)
);

/****** Table Date ******/
CREATE TABLE Date(
	DateKey int GENERATED BY DEFAULT AS IDENTITY,
	Date date NULL,
	DayNbWeek smallint NULL,
	DayNameWeek varchar(10) NULL,
	DayNbMonth smallint NULL,
	DayNbYear smallint NULL,
	WeekNbYear smallint NULL,
	MonthNumber smallint NULL,
	MonthName varchar(10) NULL,
	Quarter smallint NULL,
	Semester smallint NULL,
	Year int NULL,
	CONSTRAINT PK_Date_DateKey PRIMARY KEY (DateKey)
);

/****** Table Employee ******/
CREATE TABLE Employee(
	EmployeeKey int NOT NULL,
	FirstName varchar(10) NOT NULL,
	LastName varchar(20) NOT NULL,
	Title varchar(30) NULL,
	TitleOfCourtesy varchar(25) NULL,
	BirthDate date NULL,
	HireDate date NULL,
	Address varchar(60) NULL,
	City varchar(15) NULL,
	Region varchar(15) NULL,
	PostalCode varchar(10) NULL,
	Country varchar(15) NULL,
	SupervisorKey int NULL,
	CONSTRAINT PK_Employee_EmployeeKey PRIMARY KEY (EmployeeKey)
);

/****** Table Sales ******/
CREATE TABLE Sales(
	CustomerKey int NOT NULL,
	EmployeeKey int NOT NULL,
	OrderDateKey int NOT NULL,
	DueDateKey int NOT NULL,
	ShippedDateKey int NOT NULL,
	ShipperKey int NOT NULL,
	ProductKey int NOT NULL,
	SupplierKey int NULL,
	OrderNo int NOT NULL,
	OrderLineNo int NOT NULL,
	UnitPrice money NOT NULL,
	Quantity smallint NOT NULL,
	Discount real NOT NULL,
	SalesAmount money NOT NULL,
	Freight money NOT NULL
);

/****** Table Shipper ******/
CREATE TABLE Shipper(
	ShipperKey int NOT NULL,
	CompanyName varchar(40) NOT NULL,
	CONSTRAINT PK_Shipper_ShipperKey PRIMARY KEY (ShipperKey)
);

/****** Table Territories ******/
CREATE TABLE Territories(
	EmployeeKey int NOT NULL,
	CityKey int NOT NULL,
	CONSTRAINT PK_Territories_EmployeeKey_CityKey PRIMARY KEY (EmployeeKey, CityKey)
);







