/****** Index AK_Customer_CustomerID ******/
ALTER TABLE Customer ADD CONSTRAINT AK_Customer_CustomerID UNIQUE (CustomerID);

/****** Index AK_Date_Date ******/
ALTER TABLE Date ADD CONSTRAINT AK_Date_Date UNIQUE (Date);

/****** Index AK_Sales_OrderNo_OrderLineNo ******/
ALTER TABLE Sales ADD CONSTRAINT AK_Sales_OrderNo_OrderLineNo UNIQUE (OrderNo, OrderLineNo);

ALTER TABLE City ADD CONSTRAINT FK_City_State FOREIGN KEY(StateKey)
REFERENCES State (StateKey);

ALTER TABLE Country ADD CONSTRAINT FK_Country_Continent FOREIGN KEY(ContinentKey)
REFERENCES Continent (ContinentKey);

ALTER TABLE Customer ADD CONSTRAINT FK_Customer_City FOREIGN KEY(CityKey)
REFERENCES City (CityKey);

ALTER TABLE Employee ADD CONSTRAINT FK_Employee_Employee FOREIGN KEY(SupervisorKey)
REFERENCES Employee (EmployeeKey);

ALTER TABLE Product ADD CONSTRAINT FK_Product_Category FOREIGN KEY(CategoryKey)
REFERENCES Category (CategoryKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Customer FOREIGN KEY(CustomerKey)
REFERENCES Customer (CustomerKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Date1 FOREIGN KEY(OrderDateKey)
REFERENCES Date (DateKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Date2 FOREIGN KEY(DueDateKey)
REFERENCES Date (DateKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Date3 FOREIGN KEY(ShippedDateKey)
REFERENCES Date (DateKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Employee FOREIGN KEY(EmployeeKey)
REFERENCES Employee (EmployeeKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Product FOREIGN KEY(ProductKey)
REFERENCES Product (ProductKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Shipper FOREIGN KEY(ShipperKey)
REFERENCES Shipper (ShipperKey);

ALTER TABLE Sales ADD CONSTRAINT FK_Sales_Supplier FOREIGN KEY(SupplierKey)
REFERENCES Supplier (SupplierKey);

ALTER TABLE State ADD CONSTRAINT FK_State_Country FOREIGN KEY(CountryKey)
REFERENCES Country (CountryKey);

ALTER TABLE Supplier ADD CONSTRAINT FK_Supplier_City FOREIGN KEY(CityKey)
REFERENCES City (CityKey);

ALTER TABLE Territories ADD CONSTRAINT FK_Territories_City FOREIGN KEY(CityKey)
REFERENCES City (CityKey);

ALTER TABLE Territories ADD CONSTRAINT FK_Territories_Employee FOREIGN KEY(EmployeeKey)
REFERENCES Employee (EmployeeKey);


